```app.component.ts
import { Component } from "@angular/core";
import { AgGridAngular } from "ag-grid-angular";
import "./styles.css";
import {
  ClientSideRowModelModule,
  ColDef,
  ColGroupDef,
  GridApi,
  GridOptions,
  GridReadyEvent,
  INumberFilterParams,
  ModuleRegistry,
  NumberFilterModule,
  TextFilterModule,
  ValidationModule,
  ValueGetterParams,
} from "ag-grid-community";

ModuleRegistry.registerModules([
  TextFilterModule,
  ClientSideRowModelModule,
  NumberFilterModule,
  ...(process.env.NODE_ENV !== "production" ? [ValidationModule] : []),
]);

@Component({
  selector: "my-app",
  standalone: true,
  imports: [AgGridAngular],
  template: `<div class="test-container">
    <div class="test-header">
      <div class="test-label">Include NULL<br />in age:</div>
      <label
        ><input
          type="checkbox"
          id="checkboxEquals"
          (change)="updateParams('Equals')"
        />&nbsp;equals</label
      >
      <label
        ><input
          type="checkbox"
          id="checkboxNotEqual"
          (change)="updateParams('NotEqual')"
        />&nbsp;notEqual</label
      >
      <label
        ><input
          type="checkbox"
          id="checkboxLessThan"
          (change)="updateParams('LessThan')"
        />&nbsp;lessThan</label
      >
      <label
        ><input
          type="checkbox"
          id="checkboxGreaterThan"
          (change)="updateParams('GreaterThan')"
        />&nbsp;greaterThan</label
      >
      <label
        ><input
          type="checkbox"
          id="checkboxRange"
          (change)="updateParams('Range')"
        />&nbsp;inRange</label
      >
    </div>
    <ag-grid-angular
      style="width: 100%; height: 100%;"
      [columnDefs]="columnDefs"
      [defaultColDef]="defaultColDef"
      [rowData]="rowData"
      (gridReady)="onGridReady($event)"
    />
  </div> `,
})
export class AppComponent {
  private gridApi!: GridApi;

  columnDefs: ColDef[] = originalColumnDefs;
  defaultColDef: ColDef = {
    flex: 1,
    minWidth: 100,
  };
  rowData: any[] | null = [
    {
      athlete: "Alberto Gutierrez",
      age: 36,
    },
    {
      athlete: "Niall Crosby",
      age: 40,
    },
    {
      athlete: "Sean Landsman",
      age: null,
    },
    {
      athlete: "Robert Clarke",
      age: undefined,
    },
  ];

  updateParams(toChange: string) {
    const value: boolean = (
